const NORMALIZED_MAP: Record<string, EvidenceParagraph[]> = {}
Object.keys(RAW).forEach(k => { NORMALIZED_MAP[normalizeAr(k)] = RAW[k] })

// تعطيها اسم المؤشر فترجع مصفوفة فقرات التقييم (أو null لو المؤشر غير مغطى بالدليل المصدر)
export function getEvidenceGuide(indicatorName: string): EvidenceParagraph[] | null {
  const key = normalizeAr(indicatorName)
  if (NORMALIZED_MAP[key]) return NORMALIZED_MAP[key]
  for (const k of Object.keys(NORMALIZED_MAP)) {
    if (k.includes(key) || key.includes(k)) return NORMALIZED_MAP[k]
  }
  return null
}